import collections.abc

def _validate_value(value, definition):
    """
    Helper function to validate a single value against its definition.
    Handles primitive types, nested dictionaries, and lists.
    """
    expected_type = None

    if isinstance(definition, type):
        # Simple type definition, e.g., str, int, (str, type(None))
        expected_type = definition
    elif isinstance(definition, collections.abc.Mapping):
        # Complex definition dictionary, e.g., {'type': str, 'required': True}
        expected_type = definition.get('type')
        if expected_type is None:
            # If 'type' is missing, try to infer based on other keys (e.g., 'schema' implies dict)
            if 'schema' in definition:
                expected_type = dict
            elif 'item_type' in definition or 'item_schema' in definition:
                expected_type = list
            else:
                # Malformed schema: a dictionary definition must specify 'type', 'schema', 'item_type', or 'item_schema'
                return False
    else:
        # Malformed schema: definition is neither a type nor a dictionary
        return False

    # Check if the value's type matches the expected type(s)
    if not isinstance(value, expected_type):
        return False

    # Further validation for complex types (dict, list)
    if expected_type is dict:
        if 'schema' in definition:
            return _validate_object(value, definition['schema'])
        # If type is dict, but no 'schema' provided, any dictionary is considered valid.
        return True
    elif expected_type is list:
        if 'item_type' in definition:
            item_expected_type = definition['item_type']
            for item in value:
                if not isinstance(item, item_expected_type):
                    return False
            return True
        elif 'item_schema' in definition:
            item_expected_schema = definition['item_schema']
            for item in value:
                if not isinstance(item, collections.abc.Mapping):
                    # Elements in a list of objects must be dictionary-like
                    return False
                if not _validate_object(item, item_expected_schema):
                    return False
            return True
        # If type is list, but no item_type/schema, any list is considered valid.
        return True
    else:
        # Primitive types (str, int, float, bool, type(None), etc.) have their type checked above.
        return True

def _validate_object(data, schema):
    """
    Helper function to validate a dictionary (object) against a schema.
    """
    if not isinstance(data, collections.abc.Mapping):
        return False

    for field_name, field_definition in schema.items():
        is_required = False
        if isinstance(field_definition, collections.abc.Mapping):
            is_required = field_definition.get('required', False)
        # If field_definition is a type directly (e.g., str), it's not explicitly required.

        if field_name not in data:
            if is_required:
                return False  # Required field is missing
            else:
                continue  # Optional field is missing, which is fine

        value = data[field_name]
        if not _validate_value(value, field_definition):
            return False

    # By default, extra fields in the response that are not defined in the schema are ignored.
    # To disallow extra fields, you would add a loop like this:
    # for field_name in data:
    #     if field_name not in schema:
    #         return False

    return True

def validate_api_response(response, schema):
    """
    Validates an API response (typically a dictionary) against a given schema.

    The schema defines the expected structure, types, and required fields.

    Schema Definition:
    - A schema is a dictionary where keys are field names.
    - Values can be:
        1. A Python type (e.g., `str`, `int`, `float`, `bool`, `list`, `dict`, `type(None)`).
           This implies the field is optional by default.
           Example: `{"name": str}`
           To allow `None` for an optional string: `{"name": (str, type(None))}`
        2. A dictionary for more detailed definition:
           - `'type'`: The expected Python type (e.g., `str`, `int`, `dict`, `list`). Required.
           - `'required'`: A boolean, `True` if the field must be present (default `False`).
           - `'schema'`: (Only if `'type'` is `dict`) A nested schema dictionary for the object's properties.
           - `'item_type'`: (Only if `'type'` is `list`) The expected Python type for elements in the list
                           if they are all of a single primitive type.
           - `'item_schema'`: (Only if `'type'` is `list`) A nested schema dictionary for elements in the list
                              if they are all objects.

    Args:
        response (collections.abc.Mapping): The API response as a dictionary-like object.
        schema (collections.abc.Mapping): The schema defining the expected structure and types.

    Returns:
        bool: True if the response conforms to the schema, False otherwise.
    """
    return _validate_object(response, schema)
